INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Intelligence Training$q$, $q$Mark sites, authors, tags, or stories as more or less interesting and NewsBlur re-ranks your feed automatically based on that training.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Unified Feed, Newsletter, and YouTube Reading$q$, $q$Follow classic RSS/Atom feeds, email newsletters, and YouTube channel uploads in a single reading interface.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Full Article Text Fetching$q$, $q$Automatically retrieves full article content for feeds that only publish truncated summaries.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Story Change Tracking$q$, $q$Detects and highlights when a previously published story has been edited after the fact.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Blurblogs Social Sharing$q$, $q$A lightweight social layer for sharing and commenting on stories you find interesting with other NewsBlur users.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Native Web, iOS, and Android Apps$q$, $q$Read across the browser and native mobile apps with synced read status and training.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$IFTTT and API Integrations$q$, $q$Automate actions from new stories using IFTTT applets or NewsBlur's public API.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Open-Source Self-Hosting$q$, $q$Full source code is published on GitHub, allowing technically capable users to run their own NewsBlur instance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Open source with a public GitHub codebase and self-hosting option$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Distinctive intelligence training system for filtering noisy feeds$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Generous free tier supporting up to 64 sites$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Long, independently-run track record dating back to 2009$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Full-text fetching handles publishers that only ship truncated feeds$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Interface feels dated next to newer readers like Feedly or Inoreader$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Free tier is capped at 64 sites, which power users will exceed quickly$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Small, largely solo-founder team means slower feature development$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Premium Archive at $99 per year is pricier than most competing archive features$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Mobile apps are less polished than some dedicated competitor apps$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Is NewsBlur free?$q$, $q$Yes, NewsBlur has a free tier that supports following up to 64 sites. Paid Premium plans remove that limit and add features like saved searches and a story archive.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$What is the difference between Premium and Premium Archive?$q$, $q$Premium ($36/year) unlocks unlimited feeds and removes ads. Premium Archive ($99/year) adds those same benefits plus a permanently searchable archive of every story ever published by your subscribed sites.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Can I self-host NewsBlur?$q$, $q$Yes, NewsBlur is open source and its code is published on GitHub, so technically skilled users can deploy their own instance instead of using the hosted newsblur.com service.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Does NewsBlur support newsletters and YouTube?$q$, $q$Yes, in addition to standard RSS and Atom feeds, NewsBlur lets you subscribe to email newsletters and YouTube channels and read them alongside your other feeds.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$What happened to NewsBlur when Google Reader shut down?$q$, $q$When Google announced Google Reader's shutdown in March 2013, NewsBlur's subscriber base jumped from about 1,500 to over 60,000 users almost overnight, as readers looked for alternatives.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$How does NewsBlur's intelligence training work?$q$, $q$You can mark sites, authors, tags, or individual stories as more or less interesting, and NewsBlur uses that feedback to automatically re-rank and filter future stories in your feed.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Is there a free trial for NewsBlur Premium?$q$, $q$Yes, NewsBlur offers a 30-day free trial of its paid plans with no credit card required.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Power Reading Across Many Sources$q$, $q$Follow dozens or hundreds of blogs, newsletters, and YouTube channels in one place with intelligence training to surface what matters.$q$, $q$Professionals and power readers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Research and Source Monitoring$q$, $q$Use the searchable Premium Archive to track how coverage of a topic has evolved across many sources over time.$q$, $q$Journalists and researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Privacy-Focused Self-Hosted Reading$q$, $q$Deploy NewsBlur's open-source codebase on your own server for full control over your reading data.$q$, $q$Privacy-conscious technical users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Free$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["Follow up to 64 sites","Basic intelligence training","Web and mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Premium$q$, $q$$36/year$q$, $q$Annual$q$, NULL, $q$["Unlimited sites","Saved searches","No ads"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Premium Archive$q$, $q$$99/year$q$, $q$Annual$q$, NULL, $q$["Everything in Premium","Full searchable story archive","Unlimited historical search"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$Premium Pro$q$, $q$$29/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited sites","Saved searches","No ads","Monthly billing option"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$NewsBlur is a personal RSS and news reading service, originally built by Samuel Clay in 2009 and still largely run as an independent, open-source project out of New York City. It pulls together traditional RSS and Atom feeds, email newsletters, and YouTube channel uploads into a single reading experience, and it became one of the best-known destinations for readers displaced when Google shut down Google Reader in 2013.$q$, $q$What sets NewsBlur apart from most feed readers is its 'intelligence training' system: users can mark specific sites, authors, tags, or individual stories as more or less interesting, and NewsBlur uses that signal to automatically re-rank and filter future stories, turning a firehose of feeds into a more curated river of news.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Beyond feed aggregation, NewsBlur fetches full article text for publishers that only ship truncated summaries, tracks and visibly highlights when a published story has been edited, and lets users share and discuss stories through Blurblogs, its lightweight social layer. It ships with native web, iOS, and Android apps, plus an API and IFTTT integration for people who want to automate actions around new content.$q$, $q$Because NewsBlur is open source (its full codebase lives on GitHub), technically capable users can run their own self-hosted instance instead of relying on the hosted newsblur.com service, giving privacy-conscious readers an alternative most commercial RSS tools do not offer.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$NewsBlur uses a freemium model. The free tier supports following up to 64 sites with core reading features, which is enough for many casual users. Paid tiers remove that cap and add extras: Premium is $36 per year and includes unlimited feeds, saved searches, and no ads; Premium Archive is $99 per year and adds a fully searchable historical archive of every story ever published by any subscribed site.$q$, $q$For people who prefer monthly billing, Premium Pro is available at $29 per month. All paid tiers include a 30-day free trial that does not require a credit card, making it easy to evaluate the intelligence training system before committing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('70519451-7711-4cb1-9596-53310b5b53d4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Self-Hosted Deployment$q$, $q$Run your own instance of Newspipe on your own server for full control of your feed data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Multi-User Support$q$, $q$A single Newspipe instance can serve multiple user accounts, useful for small teams or households.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$REST API for Feed Management$q$, $q$Manage feeds and articles programmatically through Newspipe's API.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$OPML Import and Export$q$, $q$Migrate feed subscriptions to and from Newspipe using standard OPML files.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Full Account JSON Export$q$, $q$Export or import an entire account, including feeds and settings, as a portable JSON file.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Article Search and Favorites$q$, $q$Search across saved articles and bookmark favorites for later reading.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Inactive Feed Detection$q$, $q$Automatically flags feeds that have stopped publishing so they can be cleaned up.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$AGPLv3 Open-Source License$q$, $q$Full source code is published under the AGPLv3 license, allowing inspection, modification, and redistribution.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Completely free and open source under AGPLv3$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Full data ownership through self-hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Lightweight, straightforward Python and Flask stack$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Strong data portability with OPML and full JSON account export$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Supports multiple users on a single instance$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Requires technical skill to self-host, including git, Poetry, npm, and Python 3.10+$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$No official managed or hosted version is offered$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Smaller community than more established self-hosted readers like FreshRSS or Tiny Tiny RSS$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Documentation is limited compared to larger open-source projects$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$No official native mobile apps$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Is Newspipe free?$q$, $q$Yes, Newspipe is entirely free and open source under the AGPLv3 license, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Do I need to self-host Newspipe?$q$, $q$Yes, there is no official hosted service; Newspipe is designed to be deployed on your own server.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Who created Newspipe?$q$, $q$Newspipe is created and maintained by developer Cedric Bonhomme, hosted primarily on Sourcehut with a GitHub mirror.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Does Newspipe support multiple users?$q$, $q$Yes, a single Newspipe instance can host multiple user accounts, making it suitable for small teams or shared use.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Can I export my data from Newspipe?$q$, $q$Yes, Newspipe supports OPML export/import for feeds and full account export/import as JSON files.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$What license does Newspipe use?$q$, $q$Newspipe is released under the GNU Affero General Public License version 3 (AGPLv3).$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Where is Newspipe's source code hosted?$q$, $q$The primary repository is on Sourcehut at git.sr.ht/~cedric/newspipe, with a mirror on GitHub at github.com/cedricbonhomme/newspipe.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Privacy-Focused Self-Hosted Reading$q$, $q$Run your own RSS reader instance so subscription and reading data never passes through a third-party service.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Small Team or Household Feed Reader$q$, $q$Use Newspipe's multi-user support to give a small group shared access to a single self-hosted instance.$q$, $q$Small teams and households$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$API-Driven Feed Management$q$, $q$Build scripts or integrations against Newspipe's API to manage feeds programmatically.$q$, $q$Developers and technical self-hosters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$Self-Hosted / Open Source$q$, $q$Free$q$, $q$Free$q$, NULL, $q$["Full source code access","Multi-user support","OPML and JSON export/import","API access"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Newspipe is a free, open-source, self-hosted RSS and news aggregator created by developer Cedric Bonhomme. Built with Python, Flask, asyncio, and SQLAlchemy, it is released under the AGPLv3 license, with its primary repository hosted on Sourcehut and a mirror on GitHub.$q$, $q$Unlike hosted commercial RSS readers, Newspipe has no company behind it and no hosted service to sign up for. It is designed to be deployed by an individual or small team on their own server, giving full ownership and control over feed data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Newspipe supports multiple user accounts on a single instance, an API for programmatic feed management, and OPML import/export for migrating subscriptions between readers. It also supports exporting and importing a full account as JSON, giving users a clean way to back up or transfer their data.$q$, $q$Other features include article search and favorites/bookmarking, plus automatic detection of feeds that have gone inactive so administrators can keep a subscription list current.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Newspipe is entirely free and open source, with no subscription tiers, premium feature gates, or official hosted plans offered by the maintainer. The only cost involved is whatever infrastructure a user chooses to run it on.$q$, $q$Deployment requires git, Poetry, npm, and Python 3.10 or newer, and for production the project recommends running behind Gunicorn or mod_wsgi rather than Flask's built-in development server.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Universal EHR/PMS API (Synchronizer)$q$, $q$A standardized API layer that syncs patient, scheduling, and clinical data across many different underlying EHR and practice-management systems.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Online Patient Booking Widget$q$, $q$An embeddable widget that lets patients book appointments directly from a practice's website in real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Two-Way Patient Messaging$q$, $q$Automated and manual messaging with patients for reminders, confirmations, and reducing no-shows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Digital Patient Intake Forms$q$, $q$Online forms for patient intake and consent that sync directly into the practice's records.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Online Payments and Billing$q$, $q$Integrated tools for collecting patient payments and managing billing workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Insurance Verification$q$, $q$Automated checks of patient insurance eligibility ahead of appointments.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Patient Reviews Management$q$, $q$Tools to generate and manage patient reviews for the practice.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Practice Analytics Dashboard$q$, $q$Reporting on scheduling, patient communication, and practice performance metrics.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Deep, standardized two-way sync with a wide range of legacy EHR and PM systems$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Reduces no-shows through automated booking and reminder workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Well-capitalized unicorn-stage company with strong investor backing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Serves both practices directly and third-party developers via API access$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Backed by notable individual investors including Scott Belsky and Naval Ravikant$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Pricing is not publicly published and requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Primarily built for dental and medical practices rather than general-purpose use$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Integration setup with legacy PM/EHR systems can take time to configure$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Smaller overall footprint than legacy EHR incumbents like Epic$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Feature depth and pricing can vary significantly depending on the specific EHR being integrated$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$What does NexHealth do?$q$, $q$NexHealth provides a universal API that connects patient-facing tools like online booking, messaging, and payments with legacy EHR and practice-management systems, serving both healthcare practices and third-party developers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Which EHR and practice-management systems does NexHealth integrate with?$q$, $q$NexHealth's Synchronizer API is built to standardize data across a wide range of dental and medical EHR/PM systems; specific supported systems are listed on NexHealth's website and vary by practice type.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$How much does NexHealth cost?$q$, $q$NexHealth does not publish detailed pricing; it offers custom pricing based on practice size and feature needs, available by contacting sales.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Who founded NexHealth?$q$, $q$NexHealth was founded in 2017 by Alamin Uddin and Waleed Asif, who met at the City College of New York.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Is NexHealth only for dental practices?$q$, $q$No, NexHealth serves both dental and medical practices, along with Dental Service Organizations and third-party health-tech developers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$How much funding has NexHealth raised?$q$, $q$NexHealth has raised approximately $177 million across six rounds, reaching a roughly $1 billion valuation after its $125 million Series C in 2021.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Can developers build on NexHealth's API?$q$, $q$Yes, NexHealth offers API access so third-party health-tech developers can build products on top of its universal EHR integration layer.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Automated Patient Booking and Communication$q$, $q$Practices use NexHealth to let patients self-schedule online and receive automated reminders that reduce no-shows.$q$, $q$Dental and medical practices$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Multi-Location Scheduling Management$q$, $q$Dental Service Organizations use NexHealth to standardize booking and patient communication across many locations and EHR systems.$q$, $q$DSOs and multi-location practice groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$EHR Integration for Third-Party Products$q$, $q$Health-tech developers use NexHealth's Synchronizer API to integrate their own products with multiple EHR/PM systems without building custom point integrations.$q$, $q$Health-tech developers and vendors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$Custom$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["Universal EHR/PMS API access","Patient booking and messaging tools","Payments and forms","Pricing based on practice size and modules"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$NexHealth was founded in San Francisco in 2017 by Alamin Uddin and Waleed Asif, who met as students at the City College of New York. The company built a 'universal API,' called the Synchronizer, that sits on top of legacy EHR and practice-management systems, letting patient booking, messaging, and payment products sync data with those systems without each vendor building its own point-to-point integration.$q$, $q$The company reached unicorn status in 2021 after a $125 million Series C round pushed its valuation to about $1 billion, with total funding estimated at roughly $177 million across six rounds. It primarily serves dental and medical practices, including multi-location Dental Service Organizations, as well as third-party health-tech developers who build on its API.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$NexHealth's product suite includes an embeddable online booking widget, two-way patient messaging and appointment reminders, digital intake and consent forms, integrated payments and billing, insurance eligibility verification, and review management, all kept in sync with the practice's underlying EHR or PM system in near real time.$q$, $q$The Synchronizer API is the technical core of the platform: it standardizes data across many different underlying EHR and practice-management systems, which is what allows both NexHealth's own patient-facing tools and third-party developer products to read and write practice data through a single interface.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('98f9f304-96e1-4abd-9d15-b4cb9d09fcfc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$NexHealth does not publish detailed pricing on its website. As a B2B SaaS and API platform, pricing is customized based on practice size, the specific modules a practice needs (booking, messaging, payments, forms), and, for developers, the scope of API access required.$q$, $q$Prospective customers and developers are directed to contact NexHealth's sales team for a tailored quote rather than selecting from published self-serve tiers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Self-Hosted Video and Audio Calls$q$, $q$One-to-one and group calls running entirely on infrastructure the organization controls.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$End-to-End Encrypted Calls$q$, $q$Optional end-to-end encryption for sensitive calls on both web and desktop clients.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Screen Sharing with Zoom and Pan$q$, $q$Share your screen with participants able to zoom and pan into shared content for detail review.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Call Recording with Consent Notices$q$, $q$Record calls with automatic notifications to participants that recording is in progress.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Breakout Rooms and Lobby Controls$q$, $q$Split larger meetings into breakout rooms and use a waiting-room lobby to control who joins.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Guest Access$q$, $q$Invite external participants to join calls without requiring them to have a Nextcloud account.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Deep Nextcloud Integration$q$, $q$Combine calls and chat with file sharing, Deck task boards, and collaborative document editing in one interface.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$High Performance Backend for Large Webinars$q$, $q$A separately licensed add-on that scales a single call to hundreds or thousands of participants for large webinars.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Fully self-hosted, giving organizations complete control over data and infrastructure$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Core software is free and open source under the AGPL license$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Tight integration with the rest of the Nextcloud collaboration suite$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$End-to-end encryption option for sensitive communications$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Scales from small 1:1 calls to large webinars using the High Performance Backend$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Requires self-hosting or a hosting partner rather than a plug-and-play SaaS signup$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Call quality and scale depend on server resources unless the paid HPB add-on is used$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Feature depth for large-scale webinars still lags dedicated tools like Zoom$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Enterprise support pricing is not published and requires contacting sales$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Mobile and desktop app polish is less mature than commercial competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Is Nextcloud Talk free?$q$, $q$Yes, the core Nextcloud Talk software is free and open source under the AGPL license. Nextcloud GmbH separately sells paid Enterprise subscriptions for support and add-ons.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Do I need a Nextcloud server to use Talk?$q$, $q$Yes, Talk is a module of Nextcloud, so it requires a Nextcloud instance, either self-hosted, run by a hosting partner, or via Nextcloud's own cloud offering.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Does Nextcloud Talk support end-to-end encryption?$q$, $q$Yes, Nextcloud Talk offers end-to-end encrypted calls on both its web and desktop clients for sensitive communications.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$How many participants can join a Nextcloud Talk call?$q$, $q$Standard calls scale based on server resources; for hundreds or thousands of participants in large webinars, Nextcloud offers a separately licensed High Performance Backend.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$What is the Nextcloud Talk High Performance Backend?$q$, $q$It is a separately licensed add-on that improves call scaling and quality, enabling large-scale webinars and broadcasts with many simultaneous participants.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Can external guests join without an account?$q$, $q$Yes, Nextcloud Talk supports inviting external guests who can join calls without needing their own Nextcloud account.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$How does Nextcloud Talk differ from Zoom or Microsoft Teams?$q$, $q$Nextcloud Talk is self-hosted and open source, giving organizations full control over data and infrastructure, whereas Zoom and Microsoft Teams are commercial, vendor-hosted SaaS platforms.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Data-Sovereign Video Conferencing$q$, $q$Government agencies and EU public-sector organizations use Nextcloud Talk to keep video and chat data on infrastructure they control.$q$, $q$Public sector and regulated organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Integrated Collaboration for Nextcloud Users$q$, $q$Organizations already using Nextcloud for file sync add Talk for calls and chat without adopting a separate tool.$q$, $q$Existing Nextcloud customers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Replacing Commercial Conferencing Tools$q$, $q$IT teams self-host Talk to reduce reliance on commercial video conferencing subscriptions.$q$, $q$Privacy-conscious businesses and self-hosters$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Community$q$, $q$Free$q$, $q$Free$q$, NULL, $q$["Self-hosted core Talk features","Audio/video calls and chat","Screen sharing and recording","AGPL open-source license"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$Enterprise Subscription$q$, $q$Custom$q$, $q$Annual, from 100 users$q$, NULL, $q$["Official support","High Performance Backend option","SLAs","Priority security updates"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nextcloud Talk is the built-in audio, video, and chat module of Nextcloud, the open-source collaboration platform founded in 2016 in Stuttgart, Germany by Frank Karlitschek. Originally released as a separate app called Spreed, Talk was integrated into the core Nextcloud product and has grown into a full communications suite bundled with every Nextcloud installation.$q$, $q$Because it runs entirely on infrastructure the organization controls, Talk is positioned as a self-hosted, data-sovereign alternative to commercial tools like Zoom, Microsoft Teams, and Google Meet, an appeal that is especially strong for European public-sector bodies, government agencies, and privacy-regulated industries.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Talk supports one-to-one and group audio/video calls, text chat with file sharing, screen sharing with zoom and pan, call recording with consent notifications, breakout rooms, lobby controls, granular participant permissions, and guest access for people without a Nextcloud account. End-to-end encrypted calls are supported on both web and desktop clients.$q$, $q$Talk integrates closely with the rest of Nextcloud, so video calls, chat, file sharing, and collaborative document editing can all happen in the same session. For very large meetings, Nextcloud's separately licensed High Performance Backend scales a single call or webinar to hundreds or thousands of participants.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Nextcloud Talk software is free and open source under the AGPL license, so any organization can self-host it without licensing fees. Nextcloud GmbH separately sells Enterprise subscriptions, typically available from 100 users and up, priced per year in euros, which include official support and add-ons like the High Performance Backend.$q$, $q$Exact enterprise pricing is not publicly listed on Nextcloud's website and requires contacting sales for a quote based on user count and required support level.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6396cd5b-5f93-4e4e-a61e-b8afc0db1893', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Cloud VoIP Business Phone System$q$, $q$Reliable, cloud-hosted business phone service with unlimited US/Canada calling and HD audio quality.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Video Conferencing and Team Messaging$q$, $q$Built-in video meetings and internal team chat alongside the phone system.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Business SMS and Texting$q$, $q$Send and receive SMS messages with customers directly from your business number.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Contact Center Suite$q$, $q$Call center capabilities including routing, queuing, and reporting for support and sales teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Built-In CRM$q$, $q$Customer relationship management tools integrated directly with the communications platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$AI-Powered Call Analytics$q$, $q$AI-driven analytics and sentiment tracking on customer calls to surface insights.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Auto Attendants and Call Routing$q$, $q$Configurable auto attendants and routing rules to direct incoming calls appropriately.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Unlimited US and Canada Calling$q$, $q$Unlimited calling included within the US and Canada on Nextiva's core plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Unifies voice, video, SMS, and CRM in a single platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Strong reliability track record for enterprise-grade VoIP$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Scales from small businesses to large enterprise contact centers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Well-funded following a $200 million raise from Goldman Sachs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$24/7 customer support included on most plans$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Pricing rises quickly on higher tiers like Power and Enterprise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Advanced CX and AI features are gated behind pricier plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Onboarding and number porting can take time for larger organizations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Reported employee headcount has declined in recent years$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Contract terms and optional add-ons can add billing complexity$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$How much does Nextiva cost?$q$, $q$Nextiva's plans start around $15 per user per month for the Core plan, with Engage, Power, and Enterprise tiers ranging up to roughly $75 per user or agent per month depending on features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Who founded Nextiva?$q$, $q$Nextiva was co-founded in 2006 by Tomas Gorny and Tracy Conrad, with Gorny serving as CEO and having previously founded web-hosting company IPOWER.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Is Nextiva a VoIP-only company?$q$, $q$No, while Nextiva started as a VoIP business phone provider, it has expanded into a broader unified communications and customer experience management platform including video, messaging, CRM, and AI analytics.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Does Nextiva offer a free trial?$q$, $q$Nextiva offers demos and trial options for its plans; specifics vary by plan and are best confirmed directly on Nextiva's pricing page.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$What is Nextiva's Enterprise plan for?$q$, $q$The Enterprise plan targets large brands with high-volume customer contact needs, starting around $75 per agent per month with custom configuration.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Where is Nextiva headquartered?$q$, $q$Nextiva is headquartered in Scottsdale, Arizona, United States.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$How many businesses use Nextiva?$q$, $q$Nextiva reports serving over 100,000 businesses and more than 1 million users worldwide.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Small Business Phone Replacement$q$, $q$Small businesses replace legacy on-premises phone hardware with Nextiva's cloud VoIP system for reliable, unlimited calling.$q$, $q$Small businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Mid-Market and Enterprise Contact Centers$q$, $q$Larger organizations use Nextiva's contact center suite for call routing, queuing, and AI-driven analytics across support teams.$q$, $q$Mid-market and enterprise support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Unified Remote Team Communication$q$, $q$Distributed teams use Nextiva's combined voice, video, and messaging tools to stay connected without multiple separate apps.$q$, $q$Remote and hybrid teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Core$q$, $q$$15/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited voice and texting","HD audio quality","Auto attendants"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Engage$q$, $q$$25/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Core","Call center capabilities","Expanded routing and queuing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Power$q$, $q$$75/month$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Engage","Advanced call center capabilities","CRM integration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$Enterprise$q$, $q$From $75/agent/month$q$, $q$Custom$q$, NULL, $q$["High-volume customer contact tools","AI-powered analytics","Custom configuration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nextiva was co-founded in 2006 by Tomas Gorny and Tracy Conrad and bootstrapped from a small office in Scottsdale, Arizona, before landing its first paying customer in 2008. It has since grown into a cloud-based unified communications and customer experience platform serving more than 100,000 businesses and over 1 million users worldwide.$q$, $q$In 2021, Nextiva raised $200 million from Goldman Sachs at a valuation of roughly $2.7 billion, funding its evolution from a pure VoIP phone provider into a broader customer experience management (CXM) platform that layers CRM and AI-driven analytics on top of core voice and messaging.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Nextiva's core product is a cloud VoIP business phone system with unlimited US/Canada calling, HD audio, auto attendants, and call recording. Around that base, Nextiva layers video conferencing, team messaging, business SMS, and a contact center suite for businesses handling higher support volumes.$q$, $q$Higher tiers add a built-in CRM and AI-powered call analytics and sentiment tools, positioning Nextiva as a single platform for both internal communication and customer-facing conversations rather than requiring separate phone, CRM, and analytics tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eda726b9-eb10-4c2d-8347-89dbb3f5ee51', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Nextiva's pricing scales across four main tiers. Core starts around $15 per user per month for voice and texting aimed at small businesses. Engage starts around $25 per user per month and adds call-center capabilities, while Power starts around $75 per month with more advanced call-center features.$q$, $q$Enterprise packages for high-volume customer contact needs start around $75 per agent per month, with further customization and pricing available by contacting sales.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Cloud-Based Document Review$q$, $q$Review case documents in the cloud with tools designed for large-scale litigation matters.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Unlimited Data Upload, Processing, and Hosting$q$, $q$No per-gigabyte fees for uploading, processing, or hosting case data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Technology-Assisted Review (TAR)$q$, $q$Predictive coding tools to speed up review of large document sets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Case and Matter Management$q$, $q$Organize case data, custodians, and workflows within a unified matter management system.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Trial Presentation and Exhibit Preparation$q$, $q$Tools for preparing and presenting exhibits during trial.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Free OCR and Imaging$q$, $q$Optical character recognition and document imaging included at no extra data-based cost.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Production and Export Tools$q$, $q$Generate and export discovery productions for opposing counsel or regulators.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Per-User Licensing With No Data Fees$q$, $q$Pricing based purely on user seats, with no charges for co-counsel or outside experts accessing a case.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$No per-gigabyte data fees, giving predictable per-user pricing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Free unlimited data upload, hosting, OCR, and productions$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$No extra charge for co-counsel or outside experts accessing a case$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Long operating history in eDiscovery, founded in 2001$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Combines document review, case management, and trial prep in one platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Detailed pricing is not published and requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Third-party sources report widely varying costs, creating uncertainty for buyers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Smaller market presence than category leaders like Relativity$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Learning curve for teams new to TAR and predictive coding workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Support is based out of Chicago, which may not suit all time zones$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Does Nextpoint charge for data storage?$q$, $q$No, Nextpoint offers unlimited free data upload, processing, hosting, OCR, and imaging, and instead charges based on the number of user seats.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$How much does Nextpoint cost?$q$, $q$Nextpoint does not publish detailed pricing publicly; costs are per-user and vary by tier, so prospective customers should contact Nextpoint directly for a quote.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$What is Nextpoint used for?$q$, $q$Nextpoint is used for cloud-based eDiscovery, document review, case management, and trial preparation by law firms and corporate legal departments.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$When was Nextpoint founded?$q$, $q$Nextpoint was founded in 2001 in Chicago, Illinois.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Does Nextpoint support predictive coding?$q$, $q$Yes, Nextpoint includes technology-assisted review (TAR) and predictive coding tools to speed up large document reviews.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Can outside counsel access a Nextpoint case for free?$q$, $q$Yes, Nextpoint does not charge extra fees for co-counsel or outside experts who need access to a shared case.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$What are Nextpoint's main competitors?$q$, $q$Nextpoint competes with eDiscovery platforms such as Relativity, Logikcull, Everlaw, and DISCO.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Litigation Document Review$q$, $q$Law firms use Nextpoint to review and manage large volumes of case documents without worrying about data-volume costs.$q$, $q$Law firms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Recurring Corporate eDiscovery$q$, $q$Corporate legal departments use Nextpoint for recurring regulatory and litigation matters with predictable per-user costs.$q$, $q$Corporate legal departments$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Trial Preparation and Presentation$q$, $q$Litigation support teams use Nextpoint's exhibit and presentation tools to prepare for trial.$q$, $q$Litigation support teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$Custom / Contact Sales$q$, $q$Custom$q$, $q$Per-user, contact sales$q$, NULL, $q$["Per-user licensing, no data fees","Unlimited upload, hosting, OCR","Document review and TAR","Case management and trial prep"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nextpoint is a Chicago-based company, founded in 2001, that provides cloud-based eDiscovery and litigation support software for law firms and corporate legal departments. Its core differentiator in a market historically dominated by per-gigabyte pricing is a per-user subscription model with no charges for data upload, processing, hosting, OCR, imaging, or productions.$q$, $q$The platform covers the full litigation support lifecycle, from document review and technology-assisted review through case management, trial preparation, and production/export, positioning it as an alternative to enterprise eDiscovery platforms like Relativity for teams that want more predictable costs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Nextpoint provides cloud-based document review with technology-assisted review (TAR) and predictive coding to accelerate large review projects, alongside case and matter management tools and trial presentation and exhibit preparation features for litigation teams.$q$, $q$A key operational feature is Nextpoint's data policy: unlimited free data upload, processing, hosting, OCR, and imaging, with no additional fees charged for co-counsel or outside experts who need access to a shared case.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5b84747d-9c0b-41c9-af25-ea0cdbd81392', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Nextpoint prices its subscriptions on a per-user, per-seat basis rather than by data volume, but it does not publish detailed rate cards publicly. Third-party review sites report a wide range of reported per-user monthly costs, reflecting different tiers and feature sets rather than a single confirmed price point.$q$, $q$Because published figures vary significantly across sources, prospective customers should contact Nextpoint's sales team directly for a current, accurate quote based on team size and case requirements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Markdown and MDX-Based Content$q$, $q$Write documentation and content pages in Markdown or MDX, combining prose with interactive React components.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Built on Next.js$q$, $q$Inherits Next.js rendering features including Server Components, Client Components, ISR, and the App Router.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Pre-Built Documentation Components$q$, $q$Ships ready-made components like Callout, Cards, Tabs, FileTree, and Steps for common documentation patterns.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Built-In Full-Text Search$q$, $q$Fast search powered by Pagefind, indexed automatically at build time with no third-party search service required.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Dark Mode and RTL Support$q$, $q$Dark mode is enabled by default, and right-to-left layouts are supported out of the box for internationalized docs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Git-Based Last Edited Timestamps$q$, $q$Automatically displays when a page was last edited, sourced from git commit history.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$TSDoc API Reference Generation$q$, $q$Generates API reference documentation automatically from TypeScript type definitions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Official Docs and Blog Themes$q$, $q$Two official, customizable themes are included for building documentation sites or blogs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Completely free and open source under the MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Built on Next.js, inheriting React ecosystem tooling and performance features$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Fast built-in search without needing a third-party service$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Fits naturally into a git-based, docs-as-code developer workflow$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Used by well-known open-source projects such as SWR and shadcn/ui$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Requires familiarity with React and Next.js, less approachable for non-developers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Smaller plugin ecosystem than more established Docusaurus$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$No hosted or managed offering, teams must deploy and host it themselves$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Customization beyond the two official themes requires manual development work$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Advanced customization documentation can lag behind the latest releases$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Is Nextra free to use?$q$, $q$Yes, Nextra is completely free and open source under the MIT license, with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$What is Nextra built on?$q$, $q$Nextra is built directly on top of Next.js and inherits its rendering model, including Server Components and Incremental Static Regeneration.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Does Nextra support MDX?$q$, $q$Yes, Nextra fully supports MDX, allowing React components to be embedded directly inside Markdown content.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Does Nextra include search out of the box?$q$, $q$Yes, Nextra automatically indexes content at build time and provides fast full-text search through Pagefind without needing a third-party search service.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$How is Nextra different from Docusaurus?$q$, $q$Nextra is built directly on Next.js and leans on the React/Next.js ecosystem, while Docusaurus is a standalone React-based framework with its own plugin ecosystem and does not require Next.js.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Who maintains Nextra?$q$, $q$Nextra was created by Shu Ding and Paco Coursey in 2020 and is maintained as an open-source project with significant contributions from The Guild.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Can I use Nextra for a blog instead of documentation?$q$, $q$Yes, Nextra ships an official blog theme in addition to its documentation theme, so it can be used for content sites and blogs as well.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Open-Source Project Documentation$q$, $q$Open-source projects use Nextra to build fast documentation sites directly from Markdown files in their repository.$q$, $q$Open-source maintainers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Docs-as-Code Workflows$q$, $q$Engineering teams use Nextra so documentation changes go through the same git, pull request, and CI/CD process as application code.$q$, $q$Engineering and technical writing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Developer-Focused Blogs and Content Sites$q$, $q$Developers use Nextra's blog theme to build fast, MDX-powered blogs and marketing pages on Next.js.$q$, $q$Developers and technical bloggers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$Open Source$q$, $q$Free$q$, $q$Free$q$, NULL, $q$["MIT license","Docs and blog themes","Built-in search","All core components included"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nextra is an open-source, MIT-licensed framework built on top of Next.js, created in 2020 by Shu Ding and Paco Coursey and now maintained with significant contributions from The Guild. It turns Markdown and MDX files into fast, content-focused websites, most commonly used for documentation sites, blogs, and marketing pages.$q$, $q$Because Nextra is built directly on Next.js, it inherits the framework's rendering capabilities, including Server Components and Incremental Static Regeneration, while adding a documentation-specific layer of components and conventions on top.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Nextra ships pre-built components frequently needed in documentation, including Callout, Cards, FileTree, Steps, Tabs, and an interactive Playground, plus TSDoc integration for generating API references from TypeScript types. It automatically indexes content at build time and provides fast full-text search via Pagefind without needing a third-party search service.$q$, $q$Other built-in features include dark mode by default, SEO metadata handling, RTL layout support, and automatic 'last edited' timestamps pulled from git history. Nextra offers two official themes, one for documentation and one for blogs, both customizable with standard Next.js styling tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Nextra is completely free and open source under the MIT license, with no subscription tiers, paid features, or company behind it. Since it is a framework rather than a hosted service, there are no Nextra-specific fees at all.$q$, $q$Any costs a team incurs come entirely from where they choose to deploy the resulting Next.js site, such as Vercel, Netlify, or any other Node-compatible hosting provider.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('81e4c7de-ab42-4127-ae48-4dd99e1894fb', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Written From Scratch in C$q$, $q$Not derived from earlier ircd codebases, resulting in a smaller, more auditable implementation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$IPv6 and SSL/TLS Support$q$, $q$Native IPv6 support plus SSL/TLS encryption for client-server and server-server links.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$PAM-Based Authentication$q$, $q$Integrates with Pluggable Authentication Modules for system-level user authentication.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Host Cloaking$q$, $q$Hides a user's real hostname or IP address to protect privacy on the network.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Dynamic IP Friendly$q$, $q$Runs reliably on hosts with dynamic IP addresses, suited for home-hosted setups.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Broad Cross-Platform Portability$q$, $q$Builds and runs on Linux, BSD variants, macOS, Solaris, AIX, IRIX, HP-UX, and Windows via WSL or Cygwin.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Lean Configuration File$q$, $q$A single, simple configuration file designed for ease of setup and maintenance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Standard IRC Mode Support$q$, $q$Implements a wide range of common IRC user and channel modes for compatibility with standard IRC clients.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Completely free and open source under the GPLv2 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Lightweight, from-scratch codebase that is easier to audit and maintain$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Very broad cross-platform support, including niche Unix variants$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Well suited for small, private networks and homelab setups$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Supports modern security features like SSL/TLS and IPv6$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$No graphical admin interface, configuration is file-based only$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Smaller community and ecosystem than InspIRCd or UnrealIRCd$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Not designed for very large-scale public IRC networks$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Requires a separate IRC client for end users since it is server software only$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Documentation is technical and assumes sysadmin familiarity with the IRC protocol$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Is ngircd free to use?$q$, $q$Yes, ngircd is free and open source under the GPLv2 license with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$What platforms does ngircd support?$q$, $q$ngircd runs on AIX, A/UX, FreeBSD, HP-UX, IRIX, Linux, macOS, NetBSD, OpenBSD, Solaris, and Windows via WSL or Cygwin.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$How is ngircd different from other IRC daemons like UnrealIRCd?$q$, $q$ngircd was written completely from scratch in C rather than being derived from earlier ircd codebases, giving it a smaller, leaner implementation aimed at small or private networks rather than very large public ones.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Does ngircd support encrypted connections?$q$, $q$Yes, ngircd supports SSL/TLS encryption for both client-to-server and server-to-server links, as well as IPv6.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Can I run ngircd on a home server with a dynamic IP?$q$, $q$Yes, ngircd is specifically designed to work well on hosts with dynamic IP addresses, making it suitable for home-hosted setups.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$What license is ngircd released under?$q$, $q$ngircd is released under the GNU General Public License version 2 (GPLv2).$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Who maintains ngircd?$q$, $q$ngircd is maintained as a community open-source project, with active development on GitHub at ngircd/ngircd, and development dating back to 2001.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Small Private IRC Networks$q$, $q$System administrators use ngircd to stand up a small, private IRC network for a team or community.$q$, $q$System administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Open-Source Project Chat$q$, $q$Open-source projects run their own ngircd instance to host a dedicated project chat channel.$q$, $q$Open-source communities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Homelab and Hobbyist IRC Servers$q$, $q$Hobbyists self-host ngircd on home servers, including those with dynamic IP addresses, for personal or nostalgia-driven IRC networks.$q$, $q$Hobbyists and homelab users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$Open Source$q$, $q$Free$q$, $q$Free$q$, NULL, $q$["GPLv2 license","Self-hosted deployment","Full feature set included","Cross-platform support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ngircd, short for 'next generation IRC daemon,' is a free and open-source IRC server whose development began in 2001. Unlike many IRC daemons descended from earlier codebases, ngircd was written entirely from scratch in C, producing a small, auditable codebase aimed at small, private, or hobbyist IRC networks rather than very large public ones.$q$, $q$The project is released under the GPLv2 license and is maintained as a community open-source effort with no commercial company behind it. It is a common recommendation on self-hosting resource lists for anyone who wants a lightweight, standards-compliant IRC server.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ngircd supports IPv6, SSL/TLS-encrypted client-to-server and server-to-server links, PAM-based authentication, IDENT requests, and character-set conversion for legacy clients. It implements a wide range of standard IRC user and channel modes and supports host cloaking to protect user privacy.$q$, $q$The server runs comfortably on hosts with dynamic IP addresses and is built for portability, supporting AIX, A/UX, FreeBSD, HP-UX, IRIX, Linux, macOS, NetBSD, OpenBSD, and Solaris, plus Windows via WSL or Cygwin, one of the broadest platform ranges among open-source IRC daemons.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ngircd is entirely free and open source under the GPLv2 license. As server infrastructure software rather than a hosted product, it has no subscription tiers, paid features, or company monetizing it.$q$, $q$Anyone can download, compile, and run ngircd at no cost; the only expense involved is whatever server or hosting environment an operator chooses to run it on.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9bad036a-a837-4c1f-9a3f-9f0c17e20ff1', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
