-- Enrichment marathon batch: NewsBlur, Newspipe, NexHealth, Nextcloud Talk, Nextiva, Nextpoint, Nextra, ngircd

-- в”Ђв”Ђ NewsBlur в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$NewsBlur is an open-source personal RSS and news reader that lets users follow blogs, newsletters, and YouTube channels, train story relevance with intelligence filters, and read full articles from a unified feed.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$New York City, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$NewsBlur Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$NewsBlur review 2026: pricing, intelligence training, newsletter and YouTube feeds, and how this open-source RSS reader compares to Feedly and Inoreader.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$NewsBlur is a personal news and RSS reading service founded in 2009 by developer Samuel Clay, who built the first working version of the product largely on the A train during his commutes in New York City before launching it publicly the same year. NewsBlur went through Y Combinator and used that period to launch Blurblogs (a social sharing layer for shared stories), native iPad and Android apps, and an expanded version of its signature 'intelligence training' system, which lets readers mark specific sites, authors, tags, or even individual stories as more or less relevant so that the reader's unified river of news can be filtered and re-ranked over time. The company is small and largely built around its solo founder, operating out of New York City with historical ties to San Francisco as well. A pivotal moment in NewsBlur's history came in March 2013, when Google announced it would shut down Google Reader, its dominant free RSS service: NewsBlur's subscriber base jumped almost overnight from roughly 1,500 paying users to more than 60,000, cementing it as one of the primary Google Reader replacements alongside Feedly and Inoreader. NewsBlur is open source, with its full codebase published on GitHub (samuelclay/NewsBlur), which means technically inclined users can self-host an instance rather than relying on the hosted service, a feature that differentiates it from most commercial RSS readers. On the product side, NewsBlur supports classic RSS and Atom feeds as well as email newsletters and YouTube channel subscriptions, fetches full article text for feeds that only publish truncated summaries, tracks and highlights changes made to already-published stories, and offers integrations such as IFTTT for automating actions based on new content. NewsBlur's pricing follows a freemium structure: the free tier allows following up to 64 sites with basic functionality, while paid tiers remove that limit and add extra features. The Premium plan costs $36 per year and unlocks unlimited feeds, saved searches, and an ad-free experience; Premium Archive costs $99 per year and adds a searchable, permanent archive of every story ever published by a subscribed site, which is useful for researchers and power users who want to search far back in time; and Premium Pro is available at $29 per month for users who prefer a monthly billing option. A 30-day free trial requiring no credit card is offered for the paid tiers. NewsBlur's target audience includes power readers, journalists, researchers, and anyone following a large number of blogs, newsletters, or channels who wants more control over relevance and signal-to-noise than a generic feed provides. Its main competitors in the RSS reader category are Feedly, Inoreader, The Old Reader, and Feedbin, along with self-hosted alternatives like FreshRSS and Tiny Tiny RSS; NewsBlur differentiates itself primarily through its intelligence training system, its open-source codebase, and its long, independently-run history dating back to before the Google Reader shutdown reshaped the RSS reader market.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '70519451-7711-4cb1-9596-53310b5b53d4';

