-- в”Ђв”Ђ Newspipe в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Newspipe is a free, self-hosted, open-source web news aggregator built with Python and Flask that lets individuals or small teams run their own multi-user RSS feed reader.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Newspipe Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Newspipe review 2026: what this free, self-hosted, open-source RSS aggregator by Cedric Bonhomme offers versus FreshRSS, Tiny Tiny RSS, and Miniflux.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Newspipe is a free and open-source, self-hosted web news aggregator created and maintained by developer Cedric Bonhomme. The project is written in Python and built on Flask, asyncio, and SQLAlchemy, and it is licensed under the GNU Affero General Public License version 3 (AGPLv3), meaning anyone can inspect, modify, and redistribute the source. Its primary source repository is hosted on Sourcehut at git.sr.ht/~cedric/newspipe, with a mirror maintained on GitHub at github.com/cedricbonhomme/newspipe. Newspipe is not a commercial product and there is no company behind it; it is a solo-maintainer, community open-source project, which places it in the same broad category as other self-hosted feed readers such as FreshRSS, Tiny Tiny RSS, and Miniflux, rather than commercial hosted services like Feedly or Inoreader. Functionally, Newspipe lets an operator run a single instance that supports multiple user accounts, making it suitable for a small team, family, or community wanting a shared but private feed reader rather than a single-user tool. It exposes an API for managing feeds programmatically, supports OPML import and export so users can migrate feed subscriptions in and out of other readers, and additionally supports exporting and importing an entire account as a JSON file, a data-portability feature aimed at giving users full ownership of their subscription and reading data rather than locking it into one platform. Newspipe includes search and favorite/bookmark functionality for saved articles, and it can automatically detect feeds that have gone inactive so operators can clean up stale subscriptions. Deployment is aimed at people comfortable with self-hosting: the documented setup process assumes git, Poetry (Python dependency management), npm, and Python 3.10 or newer are already installed, after which the repository is cloned and dependencies installed; for production use, the project recommends running behind a WSGI server such as Gunicorn or mod_wsgi rather than Flask's built-in development server. There is no pricing model in the traditional sense since Newspipe is entirely free and open source: there are no subscription tiers, no premium features gated behind payment, and no official hosted version offered by the maintainer, so all costs are limited to whatever server or hosting a user chooses to run the software on themselves. The intended audience is technically capable individuals, small teams, and privacy-focused self-hosters who want full control over their RSS reading data and are comfortable managing their own Python-based web application rather than paying for or trusting a third-party hosted RSS service. Its closest competitors in the self-hosted feed-reader space are FreshRSS, Tiny Tiny RSS (TT-RSS), and Miniflux, all of which similarly emphasize data ownership and self-management over convenience, though Newspipe has a smaller community and a narrower feature set than the more established FreshRSS and TT-RSS projects.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b15c6e92-8bbd-4dfc-b0c2-c40feb9c903a';

