-- в”Ђв”Ђ Nextra в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Nextra is an open-source static site generation framework built on top of Next.js that makes it easy to build fast, Markdown and MDX-powered documentation and content sites.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Nextra Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Nextra review 2026: features, built-in search, themes and pricing for this free, open-source Next.js documentation and static site generator framework.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Nextra was created in 2020 by Shu Ding together with Paco Coursey, and is now maintained with significant contributions from The Guild, the team also known for GraphQL Codegen and other open-source developer tooling. It is an MIT-licensed, open-source framework layered directly on top of Next.js that turns Markdown and MDX files into fast, content-focused websites, most commonly documentation sites, blogs, and marketing pages. Because it is built on Next.js, Nextra inherits the underlying framework's rendering model, including Server Components, Client Components, Incremental Static Regeneration, and the App Router, while adding a purpose-built layer of documentation UX on top of that foundation. Out of the box, Nextra ships pre-built components commonly needed in documentation: Banner, Callout, Cards, FileTree, Steps, Table, Tabs, MDXRemote, an interactive Playground component, and TSDoc integration for auto-generating API references directly from TypeScript type definitions. It automatically indexes page content at build time and provides fast full-text search through Pagefind, removing the need for a third-party search service like Algolia DocSearch. Other built-in capabilities include dark mode enabled by default, SEO metadata handling, right-to-left (RTL) layout support for internationalized documentation, and automatic 'last edited' timestamps sourced from git history. Nextra ships two official themes, a documentation theme and a blog theme, both of which are further customizable through standard Next.js styling approaches such as Tailwind CSS or CSS Modules. Because Nextra is a framework rather than a hosted product or company, it has no pricing tiers, subscriptions, or corporate entity behind it in the traditional SaaS sense: it is free to use under the MIT license, and any hosting costs depend entirely on where a team deploys the resulting Next.js site, whether Vercel, Netlify, or any Node-compatible host. Notable adoption includes prominent open-source projects and companies that use Nextra to power their own documentation, among them SWR (Vercel's data-fetching library) and shadcn/ui, along with parts of Vercel's developer-facing documentation. Nextra's main competitors in the documentation-framework space are Docusaurus (Meta's React-based documentation framework), VitePress (the Vue-based equivalent), Fumadocs (a newer Next.js-based competitor built with a similar philosophy), and commercial hosted platforms like Mintlify and GitBook that trade some of Nextra's code-first flexibility for a more polished, managed authoring experience. Nextra's core audience is front-end developers, open-source maintainers, and technical writing teams who are already comfortable with React and Next.js and want a lightweight, code-first way to ship documentation without adopting a separate CMS or hosted SaaS product. Because all content lives as Markdown/MDX files in a git repository, Nextra fits naturally into existing developer workflows, letting documentation changes go through the same pull request, code review, and CI/CD process as application code, an approach commonly described as 'docs as code.'$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '81e4c7de-ab42-4127-ae48-4dd99e1894fb';

